// Normalize incoming event records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    eventId: String(j.eventId ?? j.id ?? '').trim(),
    severity: typeof j.severity === 'string' ? j.severity.trim() : j.severity ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;
